// // This comment suggests that the circuit performs a bitwise OR operation between inputs A, B, and C, and the logical negation of input D using a bitwise AND.
module top_module(
    input A,
    input B,
    input C,
    input D,
    output Y
);wire A_and_B_and_C = A & B & C;
    wire not_D = ~D;

    assign Y = A_and_B_and_C | not_D;

endmodule
